import './App.css';

export const TodoList = () => {
  return (
    <>
    <div>
      <input placeholder='Todoを入力'/>
      <button>追加</button>
    </div>
    <div>
        <p>未完了のToDo</p>
        <ul>
        <li>
        <button>完了</button>
        <button>削除</button>
      </li>
      </ul>
    </div>
    <div></div>
    </>
  );
};
